int prep[32][3][3];
int preq[32][3][3];

pair<long long, int> get_next(int i, int cur, int bit1, int bit2) {
    long long cost = 0;
    int ns = 0;
    if(cur == 1) {
        if(bit1 == bit2) {
            cost = 0;
            ns = 1;
        }else if(bit2 < bit1) {
            cost = (1 << i);
            ns = 0;
        }else if(bit2 > bit1) {
            cost = (1 << i);
            ns = 2;
